namespace sv_222148d2a94e4e3da6f48431a21a7c10.Models;

public record UserProfile(string DisplayName, string Email, string AvatarUrl, string Bio);
public record NotificationPrefs(bool EmailNotifications, bool PushNotifications, bool WeeklyDigest, List<string> MutedChannels);
public record SecuritySettings(bool TwoFactorEnabled, DateTime? LastPasswordChange, List<ActiveSession> Sessions);
public record ActiveSession(string Id, string Device, string Location, DateTime LastActive);
public record AppearanceSettings(string Theme, string FontSize, string Language, bool CompactMode);

public interface ISettingsService
{
    Task<UserProfile> GetProfileAsync();
    Task SaveProfileAsync(UserProfile profile);
    Task<NotificationPrefs> GetNotificationPrefsAsync();
    Task SaveNotificationPrefsAsync(NotificationPrefs prefs);
    Task<SecuritySettings> GetSecuritySettingsAsync();
    Task ChangePasswordAsync(string currentPassword, string newPassword);
    Task RevokeSessionAsync(string sessionId);
    Task<AppearanceSettings> GetAppearanceAsync();
    Task SaveAppearanceAsync(AppearanceSettings settings);
}

@namespace sv_222148d2a94e4e3da6f48431a21a7c10.Components.Pages.Settings

<nav class="settings-sidebar">
    <h5 class="sidebar-title">Settings</h5>
    <ul class="nav flex-column">
        @foreach (var section in Sections)
        {
            <li class="nav-item">
                <button class="nav-link @(ActiveSection == section.Key ? "active" : "")"
                        @onclick="() => OnSectionChanged.InvokeAsync(section.Key)">
                    <span class="sidebar-icon">@section.Icon</span>
                    @section.Label
                </button>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter, EditorRequired] public string ActiveSection { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback<string> OnSectionChanged { get; set; }

    private record SectionItem(string Key, string Label, string Icon);

    private static readonly SectionItem[] Sections =
    [
        new("profile", "Profile", "👤"),
        new("notifications", "Notifications", "🔔"),
        new("security", "Security", "🔒"),
        new("appearance", "Appearance", "🎨")
    ];
}

@namespace sv_222148d2a94e4e3da6f48431a21a7c10.Components.Pages.Settings
@using sv_222148d2a94e4e3da6f48431a21a7c10.Models

<div class="settings-section">
    <h3>Profile</h3>

    @if (showSuccess)
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            Profile saved successfully!
            <button type="button" class="btn-close" @onclick="() => showSuccess = false"></button>
        </div>
    }

    <div class="row">
        <div class="col-md-8">
            <div class="mb-3">
                <label class="form-label">Display Name</label>
                <input type="text" class="form-control" @bind="displayName" />
            </div>
            <div class="mb-3">
                <label class="form-label">Email</label>
                <input type="email" class="form-control" @bind="email" />
            </div>
            <div class="mb-3">
                <label class="form-label">Bio</label>
                <textarea class="form-control" rows="4" @bind="bio"></textarea>
            </div>
        </div>
        <div class="col-md-4">
            <div class="avatar-preview">
                <label class="form-label">Avatar Preview</label>
                <div class="avatar-frame mb-2">
                    @if (!string.IsNullOrWhiteSpace(avatarUrl))
                    {
                        <img src="@avatarUrl" alt="Avatar" class="avatar-img" />
                    }
                    else
                    {
                        <div class="avatar-placeholder">No Avatar</div>
                    }
                </div>
                <div class="mb-3">
                    <label class="form-label text-muted small">Avatar URL</label>
                    <input type="url" class="form-control form-control-sm" @bind="avatarUrl" />
                </div>
            </div>
        </div>
    </div>

    <div class="d-flex gap-2">
        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@saving">
            @(saving ? "Saving..." : "Save Changes")
        </button>
        <button class="btn btn-outline-secondary" @onclick="Discard">
            Discard Changes
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public UserProfile Profile { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback<UserProfile> OnSave { get; set; }

    private string displayName = "";
    private string email = "";
    private string avatarUrl = "";
    private string bio = "";
    private bool saving;
    private bool showSuccess;

    protected override void OnParametersSet()
    {
        if (Profile is not null && !saving)
        {
            LoadFromProfile();
        }
    }

    private void LoadFromProfile()
    {
        displayName = Profile.DisplayName;
        email = Profile.Email;
        avatarUrl = Profile.AvatarUrl;
        bio = Profile.Bio;
    }

    private async Task SaveAsync()
    {
        saving = true;
        showSuccess = false;
        var updated = new UserProfile(displayName, email, avatarUrl, bio);
        await OnSave.InvokeAsync(updated);
        saving = false;
        showSuccess = true;
    }

    private void Discard()
    {
        LoadFromProfile();
        showSuccess = false;
    }
}

@namespace sv_222148d2a94e4e3da6f48431a21a7c10.Components.Pages.Settings
@using sv_222148d2a94e4e3da6f48431a21a7c10.Models

<div class="settings-section">
    <h3>Notifications</h3>

    @if (showSuccess)
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            Notification preferences saved!
            <button type="button" class="btn-close" @onclick="() => showSuccess = false"></button>
        </div>
    }

    <div class="mb-4">
        <h5>General</h5>
        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="emailNotif" @bind="emailNotifications" />
            <label class="form-check-label" for="emailNotif">Email Notifications</label>
        </div>
        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="pushNotif" @bind="pushNotifications" />
            <label class="form-check-label" for="pushNotif">Push Notifications</label>
        </div>
        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="weeklyDigest" />
            <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
        </div>
    </div>

    <div class="mb-4">
        <h5>Muted Channels</h5>
        @if (allChannels.Count == 0)
        {
            <p class="text-muted">No channels available.</p>
        }
        else
        {
            @foreach (var channel in allChannels)
            {
                <div class="form-check mb-1">
                    <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                           checked="@mutedChannels.Contains(channel)"
                           @onchange="e => ToggleChannel(channel, (bool)(e.Value ?? false))" />
                    <label class="form-check-label" for="@($"ch-{channel}")">@channel (muted)</label>
                </div>
            }
        }
    </div>

    <button class="btn btn-primary" @onclick="SaveAsync" disabled="@saving">
        @(saving ? "Saving..." : "Save Preferences")
    </button>
</div>

@code {
    [Parameter, EditorRequired] public NotificationPrefs Prefs { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback<NotificationPrefs> OnSave { get; set; }

    private bool emailNotifications;
    private bool pushNotifications;
    private bool weeklyDigest;
    private HashSet<string> mutedChannels = new();
    private bool saving;
    private bool showSuccess;

    // Represents all available channels in the system
    private List<string> allChannels = ["general", "announcements", "engineering", "design", "marketing", "random"];

    protected override void OnParametersSet()
    {
        if (Prefs is not null && !saving)
        {
            emailNotifications = Prefs.EmailNotifications;
            pushNotifications = Prefs.PushNotifications;
            weeklyDigest = Prefs.WeeklyDigest;
            mutedChannels = new HashSet<string>(Prefs.MutedChannels ?? []);
        }
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted)
            mutedChannels.Add(channel);
        else
            mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        saving = true;
        showSuccess = false;
        var updated = new NotificationPrefs(emailNotifications, pushNotifications, weeklyDigest, mutedChannels.ToList());
        await OnSave.InvokeAsync(updated);
        saving = false;
        showSuccess = true;
    }
}

@namespace sv_222148d2a94e4e3da6f48431a21a7c10.Components.Pages.Settings

<div class="card mb-4">
    <div class="card-header d-flex justify-content-between align-items-center"
         style="cursor: pointer" @onclick="() => expanded = !expanded">
        <strong>Change Password</strong>
        <span>@(expanded ? "▲" : "▼")</span>
    </div>
    @if (expanded)
    {
        <div class="card-body">
            @if (!string.IsNullOrEmpty(errorMessage))
            {
                <div class="alert alert-danger">@errorMessage</div>
            }
            @if (showSuccess)
            {
                <div class="alert alert-success">Password updated successfully!</div>
            }

            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="currentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="newPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="confirmPassword" />
            </div>
            <button class="btn btn-warning" @onclick="UpdatePasswordAsync" disabled="@updating">
                @(updating ? "Updating..." : "Update Password")
            </button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public EventCallback<(string Current, string New)> OnChangePassword { get; set; }

    private string currentPassword = "";
    private string newPassword = "";
    private string confirmPassword = "";
    private bool expanded;
    private bool updating;
    private string? errorMessage;
    private bool showSuccess;

    private async Task UpdatePasswordAsync()
    {
        errorMessage = null;
        showSuccess = false;

        if (string.IsNullOrWhiteSpace(currentPassword) ||
            string.IsNullOrWhiteSpace(newPassword))
        {
            errorMessage = "All password fields are required.";
            return;
        }

        if (newPassword != confirmPassword)
        {
            errorMessage = "New password and confirmation do not match.";
            return;
        }

        updating = true;
        try
        {
            await OnChangePassword.InvokeAsync((currentPassword, newPassword));
            showSuccess = true;
            currentPassword = "";
            newPassword = "";
            confirmPassword = "";
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            updating = false;
        }
    }
}

@namespace sv_222148d2a94e4e3da6f48431a21a7c10.Components.Pages.Settings
@using sv_222148d2a94e4e3da6f48431a21a7c10.Models

<div class="mb-4">
    <h5>Active Sessions</h5>
    @if (Sessions.Count == 0)
    {
        <p class="text-muted">No active sessions.</p>
    }
    else
    {
        <div class="table-responsive">
            <table class="table table-striped">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in Sessions)
                    {
                        <tr>
                            <td>@session.Device</td>
                            <td>@session.Location</td>
                            <td>@session.LastActive.ToString("g")</td>
                            <td>
                                @if (session.Id != CurrentSessionId)
                                {
                                    <button class="btn btn-sm btn-outline-danger"
                                            @onclick="() => PromptRevoke(session)">
                                        Revoke
                                    </button>
                                }
                                else
                                {
                                    <span class="badge bg-success">Current</span>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    }
</div>

@* Confirmation dialog *@
@if (sessionToRevoke is not null)
{
    <div class="modal-backdrop fade show"></div>
    <div class="modal d-block fade show" tabindex="-1" role="dialog">
        <div class="modal-dialog" role="document">
            <div class="modal-content">
                <div class="modal-header">
