    private bool emailNotifications;
    private bool pushNotifications;
    private bool weeklyDigest;
    private HashSet<string> mutedChannels = new();
    private bool saving;
    private bool showSuccess;

    // Represents all available channels in the system
    private List<string> allChannels = ["general", "announcements", "engineering", "design", "marketing", "random"];

