<div class="settings-section">
    <h3>Appearance</h3>

    @if (showSuccess)
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            Appearance settings saved!
            <button type="button" class="btn-close" @onclick="() => showSuccess = false"></button>
        </div>
    }

    <div class="row">
        <div class="col-md-6">
            <div class="mb-4">
                <h5>Theme</h5>
                @foreach (var t in themes)
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="theme"
                               id="@($"theme-{t}")" value="@t"
                               checked="@(theme == t)"
                               @onchange="() => theme = t" />
                        <label class="form-check-label" for="@($"theme-{t}")">@t</label>
                    </div>
                }
            </div>

            <div class="mb-4">
                <h5>Font Size</h5>
                @foreach (var fs in fontSizes)
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="fontSize"
                               id="@($"fs-{fs}")" value="@fs"
                               checked="@(fontSize == fs)"
                               @onchange="() => fontSize = fs" />
                        <label class="form-check-label" for="@($"fs-{fs}")">@fs</label>
                    </div>
                }
            </div>

            <div class="mb-4">
                <h5>Language</h5>
                <select class="form-select" @bind="language">
                    @foreach (var lang in languages)
                    {
                        <option value="@lang.Key">@lang.Value</option>
                    }
                </select>
            </div>

            <div class="mb-4">
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="compactMode" @bind="compactMode" />
                    <label class="form-check-label" for="compactMode">Compact Mode</label>
                </div>
            </div>

            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@saving">
                @(saving ? "Saving..." : "Save")
            </button>
        </div>

        <div class="col-md-6">
            <h5>Live Preview</h5>
            <div class="appearance-preview @PreviewClasses" style="@PreviewStyle">
                <div class="preview-header">
                    <strong>Sample Header</strong>
                </div>
                <div class="preview-body">
                    <p>This is a preview of your selected appearance settings.</p>
                    <button class="btn btn-sm @PreviewButtonClass">Sample Button</button>
                </div>
                <div class="preview-footer text-muted">
                    <small>Theme: @theme · Font: @fontSize · Compact: @(compactMode ? "On" : "Off")</small>
                </div>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public AppearanceSettings Settings { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string theme = "Light";
    private string fontSize = "Medium";
    private string language = "en";
    private bool compactMode;
    private bool saving;
    private bool showSuccess;

    private static readonly string[] themes = ["Light", "Dark", "System"];
    private static readonly string[] fontSizes = ["Small", "Medium", "Large"];
    private static readonly Dictionary<string, string> languages = new()
    {
        ["en"] = "English",
        ["es"] = "Español",
        ["fr"] = "Français",
        ["de"] = "Deutsch",
        ["ja"] = "日本語"
    };

    protected override void OnParametersSet()
    {
        if (Settings is not null && !saving)
        {
            theme = Settings.Theme;
            fontSize = Settings.FontSize;
            language = Settings.Language;
            compactMode = Settings.CompactMode;
        }
    }

    private string PreviewClasses
    {
        get
        {
            var classes = new List<string>();
            if (theme == "Dark") classes.Add("preview-dark");
            if (compactMode) classes.Add("preview-compact");
            classes.Add($"preview-font-{fontSize.ToLowerInvariant()}");
            return string.Join(" ", classes);
        }
    }

    private string PreviewStyle => theme == "Dark"
        ? "background-color: #1e1e1e; color: #e0e0e0; border: 1px solid #444;"
        : "background-color: #ffffff; color: #333; border: 1px solid #ddd;";

    private string PreviewButtonClass => theme == "Dark" ? "btn-outline-light" : "btn-outline-primary";

    private async Task SaveAsync()
    {
        saving = true;
        showSuccess = false;
        var updated = new AppearanceSettings(theme, fontSize, language, compactMode);
        await OnSave.InvokeAsync(updated);
        saving = false;
        showSuccess = true;
    }
}

