{"path": "/tmp/sv-222148d2a94e4e3da6f48431a21a7c10/Components/Pages/Settings/NotificationsSection.razor", "file_text": "@namespace sv_222148d2a94e4e3da6f48431a21a7c10.Components.Pages.Settings
@using sv_222148d2a94e4e3da6f48431a21a7c10.Models

<div class="settings-section">
    <h3>Notifications</h3>

    @if (showSuccess)
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            Notification preferences saved!
            <button type="button" class="btn-close" @onclick="() => showSuccess = false"></button>
        </div>
    }

    <div class="mb-4">
        <h5>General</h5>
        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="emailNotif" @bind="emailNotifications" />
            <label class="form-check-label" for="emailNotif">Email Notifications</label>
        </div>
        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="pushNotif" @bind="pushNotifications" />
            <label class="form-check-label" for="pushNotif">Push Notifications</label>
        </div>
        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="weeklyDigest" />
            <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
        </div>
    </div>

    <div class="mb-4">
        <h5>Muted Channels</h5>
        @if (allChannels.Count == 0)
        {
            <p class="text-muted">No channels available.</p>
        }
        else
        {
            @foreach (var channel in allChannels)
            {
                <div class="form-check mb-1">
                    <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                           checked="@mutedChannels.Contains(channel)"
                           @onchange="e => ToggleChannel(channel, (bool)(e.Value ?? false))" />
                    <label class="form-check-label" for="@($"ch-{channel}")">@channel (muted)</label>
                </div>
            }
        }
    </div>

    <button class="btn btn-primary" @onclick="SaveAsync" disabled="@saving">
        @(saving ? "Saving..." : "Save Preferences")
    </button>
</div>

@code {
    [Parameter, EditorRequired] public NotificationPrefs Prefs { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback<NotificationPrefs> OnSave { get; set; }

    private bool emailNotifications;
    private bool pushNotifications;
    private bool weeklyDigest;
    private HashSet<string> mutedChannels = new();
    private bool saving;
    private bool showSuccess;

    // Represents all available channels in the system
    private List<string> allChannels = ["general", "announcements", "engineering", "design", "marketing", "random"];

    protected override void OnParametersSet()
    {
        if (Prefs is not null && !saving)
        {
            emailNotifications = Prefs.EmailNotifications;
            pushNotifications = Prefs.PushNotifications;
            weeklyDigest = Prefs.WeeklyDigest;
            mutedChannels = new HashSet<string>(Prefs.MutedChannels ?? []);
        }
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted)
            mutedChannels.Add(channel);
        else
            mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        saving = true;
        showSuccess = false;
        var updated = new NotificationPrefs(emailNotifications, pushNotifications, weeklyDigest, mutedChannels.ToList());
        await OnSave.InvokeAsync(updated);
        saving = false;
        showSuccess = true;
    }
}
"}

{"path": "/tmp/sv-222148d2a94e4e3da6f48431a21a7c10/Components/Pages/Settings/ChangePasswordPanel.razor", "file_text": "@namespace sv_222148d2a94e4e3da6f48431a21a7c10.Components.Pages.Settings

<div class="card mb-4">
    <div class="card-header d-flex justify-content-between align-items-center"
         style="cursor: pointer" @onclick="() => expanded = !expanded">
        <strong>Change Password</strong>
        <span>@(expanded ? "▲" : "▼")</span>
    </div>
    @if (expanded)
    {
        <div class="card-body">
            @if (!string.IsNullOrEmpty(errorMessage))
            {
                <div class="alert alert-danger">@errorMessage</div>
            }
            @if (showSuccess)
            {
                <div class="alert alert-success">Password updated successfully!</div>
            }

            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="currentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="newPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="confirmPassword" />
            </div>
            <button class="btn btn-warning" @onclick="UpdatePasswordAsync" disabled="@updating">
                @(updating ? "Updating..." : "Update Password")
            </button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public EventCallback<(string Current, string New)> OnChangePassword { get; set; }

    private string currentPassword = "";
    private string newPassword = "";
    private string confirmPassword = "";
    private bool expanded;
    private bool updating;
    private string? errorMessage;
    private bool showSuccess;

    private async Task UpdatePasswordAsync()
    {
        errorMessage = null;
        showSuccess = false;

        if (string.IsNullOrWhiteSpace(currentPassword) ||
            string.IsNullOrWhiteSpace(newPassword))
        {
            errorMessage = "All password fields are required.";
            return;
        }

        if (newPassword != confirmPassword)
        {
            errorMessage = "New password and confirmation do not match.";
            return;
        }

        updating = true;
        try
        {
            await OnChangePassword.InvokeAsync((currentPassword, newPassword));
            showSuccess = true;
            currentPassword = "";
            newPassword = "";
            confirmPassword = "";
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            updating = false;
        }
    }
}
"}

{"path": "/tmp/sv-222148d2a94e4e3da6f48431a21a7c10/Components/Pages/Settings/ActiveSessionsTable.razor", "file_text": "@namespace sv_222148d2a94e4e3da6f48431a21a7c10.Components.Pages.Settings
@using sv_222148d2a94e4e3da6f48431a21a7c10.Models

<div class="mb-4">
    <h5>Active Sessions</h5>
    @if (Sessions.Count == 0)
    {
        <p class="text-muted">No active sessions.</p>
    }
    else
    {
        <div class="table-responsive">
            <table class="table table-striped">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in Sessions)
                    {
                        <tr>
                            <td>@session.Device</td>
                            <td>@session.Location</td>
                            <td>@session.LastActive.ToString("g")</td>
                            <td>
                                @if (session.Id != CurrentSessionId)
                                {
                                    <button class="btn btn-sm btn-outline-danger"
                                            @onclick="() => PromptRevoke(session)">
                                        Revoke
                                    </button>
                                }
                                else
                                {
                                    <span class="badge bg-success">Current</span>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    }
</div>

@* Confirmation dialog *@
@if (sessionToRevoke is not null)
{
    <div class="modal-backdrop fade show"></div>
    <div class="modal d-block fade show" tabindex="-1" role="dialog">
        <div class="modal-dialog" role="document">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                </div>
                <div class="modal-body">
                    <p>Are you sure you want to revoke the session on <strong>@sessionToRevoke.Device</strong> from <strong>@sessionToRevoke.Location</strong>?</p>
                </div>
                <div class="modal-footer">
                    <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                    <button class="btn btn-danger" @onclick="ConfirmRevokeAsync" disabled="@revoking">
                        @(revoking ? "Revoking..." : "Revoke Session")
                    </button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter, EditorRequired] public List<ActiveSession> Sessions { get; set; } = [];
    [Parameter] public string? CurrentSessionId { get; set; }
    [Parameter, EditorRequired] public EventCallback<string> OnRevoke { get; set; }

    private ActiveSession? sessionToRevoke;
    private bool revoking;

    private void PromptRevoke(ActiveSession session)
    {
        sessionToRevoke = session;
    }

    private void CancelRevoke()
    {
        sessionToRevoke = null;
    }

    private async Task ConfirmRevokeAsync()
    {
        if (sessionToRevoke is null) return;
        revoking = true;
        await OnRevoke.InvokeAsync(sessionToRevoke.Id);
        revoking = false;
        sessionToRevoke = null;
    }
}
"}

{"path": "/tmp/sv-222148d2a94e4e3da6f48431a21a7c10/Components/Pages/Settings/SecuritySection.razor", "file_text": "@namespace sv_222148d2a94e4e3da6f48431a21a7c10.Components.Pages.Settings
@using sv_222148d2a94e4e3da6f48431a21a7c10.Models

<div class="settings-section">
    <h3>Security</h3>

    <ChangePasswordPanel OnChangePassword="HandleChangePassword" />

    <div class="card mb-4">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center">
                <div>
                    <h5 class="mb-1">Two-Factor Authentication</h5>
                    <span class="badge @(Security.TwoFactorEnabled ? "bg-success" : "bg-secondary")">
                        @(Security.TwoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="twoFactor"
                           checked="@twoFactorEnabled"
                           @onchange="Toggle2FA" />
                </div>
            </div>
            @if (Security.LastPasswordChange.HasValue)
            {
                <p class="text-muted mt-2 mb-0">
                    Last password change: @Security.LastPasswordChange.Value.ToString("f")
                </p>
            }
        </div>
    </div>

    <ActiveSessionsTable Sessions="Security.Sessions"
                         CurrentSessionId="@currentSessionId"
                         OnRevoke="HandleRevoke" />
</div>

@code {
    [Parameter, EditorRequired] public SecuritySettings Security { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }
    [Parameter, EditorRequired] public EventCallback<string> OnRevokeSession { get; set; }
    [Parameter, EditorRequired] public EventCallback<bool> OnToggle2FA { get; set; }

    private bool twoFactorEnabled;

    // First session is treated as the current session
    private string currentSessionId => Security.Sessions.FirstOrDefault()?.Id ?? "";

    protected override void OnParametersSet()
    {
        twoFactorEnabled = Security.TwoFactorEnabled;
    }

    private async Task HandleChangePassword((string Current, string New) args)
    {
        await OnChangePassword.InvokeAsync(args);
    }

    private async Task HandleRevoke(string sessionId)
    {
        await OnRevokeSession.InvokeAsync(sessionId);
    }

    private async Task Toggle2FA(ChangeEventArgs e)
    {
        twoFactorEnabled = (bool)(e.Value ?? false);
        await OnToggle2FA.InvokeAsync(twoFactorEnabled);
    }
}
"}

