    private string theme = "Light";
    private string fontSize = "Medium";
    private string language = "en";
    private bool compactMode;
    private bool saving;
    private bool showSuccess;

    private static readonly string[] themes = ["Light", "Dark", "System"];
    private static readonly string[] fontSizes = ["Small", "Medium", "Large"];
    private static readonly Dictionary<string, string> languages = new()
    {
        ["en"] = "English",
        ["es"] = "Español",
        ["fr"] = "Français",
        ["de"] = "Deutsch",
        ["ja"] = "日本語"
    };

    protected override void OnParametersSet()
    {
        if (Settings is not null && !saving)
        {
            theme = Settings.Theme;
            fontSize = Settings.FontSize;
            language = Settings.Language;
            compactMode = Settings.CompactMode;
        }
    }

    private string PreviewClasses
    {
        get
        {
            var classes = new List<string>();
            if (theme == "Dark") classes.Add("preview-dark");
            if (compactMode) classes.Add("preview-compact");
            classes.Add($"preview-font-{fontSize.ToLowerInvariant()}");
            return string.Join(" ", classes);
        }
    }

    private string PreviewStyle => theme == "Dark"
        ? "background-color: #1e1e1e; color: #e0e0e0; border: 1px solid #444;"
        : "background-color: #ffffff; color: #333; border: 1px solid #ddd;";

    private string PreviewButtonClass => theme == "Dark" ? "btn-outline-light" : "btn-outline-primary";

    private async Task SaveAsync()
    {
        saving = true;
        showSuccess = false;
        var updated = new AppearanceSettings(theme, fontSize, language, compactMode);
        await OnSave.InvokeAsync(updated);
        saving = false;
        showSuccess = true;
    }
}
"}

