@namespace sv_222148d2a94e4e3da6f48431a21a7c10.Components.Pages.Settings
@using sv_222148d2a94e4e3da6f48431a21a7c10.Models

<div class="settings-section">
    <h3>Profile</h3>

    @if (showSuccess)
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            Profile saved successfully!
            <button type="button" class="btn-close" @onclick="() => showSuccess = false"></button>
        </div>
    }

    <div class="row">
        <div class="col-md-8">
            <div class="mb-3">
                <label class="form-label">Display Name</label>
                <input type="text" class="form-control" @bind="displayName" />
            </div>
            <div class="mb-3">
                <label class="form-label">Email</label>
                <input type="email" class="form-control" @bind="email" />
            </div>
            <div class="mb-3">
                <label class="form-label">Bio</label>
                <textarea class="form-control" rows="4" @bind="bio"></textarea>
            </div>
        </div>
        <div class="col-md-4">
            <div class="avatar-preview">
                <label class="form-label">Avatar Preview</label>
                <div class="avatar-frame mb-2">
                    @if (!string.IsNullOrWhiteSpace(avatarUrl))
                    {
                        <img src="@avatarUrl" alt="Avatar" class="avatar-img" />
                    }
                    else
                    {
                        <div class="avatar-placeholder">No Avatar</div>
                    }
                </div>
                <div class="mb-3">
                    <label class="form-label text-muted small">Avatar URL</label>
                    <input type="url" class="form-control form-control-sm" @bind="avatarUrl" />
                </div>
            </div>
        </div>
    </div>

    <div class="d-flex gap-2">
        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@saving">
            @(saving ? "Saving..." : "Save Changes")
        </button>
        <button class="btn btn-outline-secondary" @onclick="Discard">
            Discard Changes
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public UserProfile Profile { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback<UserProfile> OnSave { get; set; }

    private string displayName = "";
    private string email = "";
    private string avatarUrl = "";
    private string bio = "";
    private bool saving;
    private bool showSuccess;

    protected override void OnParametersSet()
    {
        if (Profile is not null && !saving)
        {
            LoadFromProfile();
        }
    }

    private void LoadFromProfile()
    {
        displayName = Profile.DisplayName;
        email = Profile.Email;
        avatarUrl = Profile.AvatarUrl;
        bio = Profile.Bio;
    }

    private async Task SaveAsync()
    {
        saving = true;
        showSuccess = false;
        var updated = new UserProfile(displayName, email, avatarUrl, bio);
        await OnSave.InvokeAsync(updated);
        saving = false;
        showSuccess = true;
    }

    private void Discard()
    {
        LoadFromProfile();
        showSuccess = false;
    }
}

