.settings-dashboard {
    display: flex;
    gap: 1.5rem;
    min-height: 70vh;
}

/* Sidebar */
::deep .settings-sidebar {
    width: 220px;
    flex-shrink: 0;
    background: #f8f9fa;
    border-radius: 8px;
    padding: 1rem 0;
    border: 1px solid #e9ecef;
    height: fit-content;
    position: sticky;
    top: 1rem;
}

::deep .sidebar-title {
    padding: 0 1rem 0.5rem;
    margin-bottom: 0.5rem;
    border-bottom: 1px solid #e9ecef;
    color: #6c757d;
    font-size: 0.75rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
}

::deep .settings-sidebar .nav-link {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.6rem 1rem;
    color: #495057;
    border: none;
    background: none;
    width: 100%;
    text-align: left;
    border-radius: 0;
    transition: background-color 0.15s, color 0.15s;
}

::deep .settings-sidebar .nav-link:hover {
    background-color: #e9ecef;
    color: #212529;
}

::deep .settings-sidebar .nav-link.active {
    background-color: #0d6efd;
    color: #fff;
    font-weight: 500;
}

::deep .sidebar-icon {
    font-size: 1.1rem;
}

/* Content area */
.settings-content {
    flex: 1;
    min-width: 0;
}

::deep .settings-section {
    background: #fff;
    border-radius: 8px;
    padding: 1.5rem;
    border: 1px solid #e9ecef;
}

::deep .settings-section h3 {
    margin-bottom: 1.25rem;
    padding-bottom: 0.75rem;
    border-bottom: 2px solid #e9ecef;
    font-size: 1.3rem;
}

/* Avatar */
::deep .avatar-frame {
    width: 120px;
    height: 120px;
    border-radius: 50%;
    overflow: hidden;
    border: 3px solid #e9ecef;
    display: flex;
    align-items: center;
    justify-content: center;
    background: #f8f9fa;
}

::deep .avatar-img {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

::deep .avatar-placeholder {
    color: #adb5bd;
    font-size: 0.85rem;
}

/* Appearance preview */
::deep .appearance-preview {
    border-radius: 8px;
    padding: 1rem;
    min-height: 180px;
    transition: all 0.2s ease;
}

::deep .appearance-preview .preview-header {
    padding-bottom: 0.5rem;
    margin-bottom: 0.75rem;
    border-bottom: 1px solid currentColor;
    opacity: 0.3;
}

::deep .appearance-preview .preview-body {
    margin-bottom: 0.75rem;
}

::deep .appearance-preview .preview-footer {
    padding-top: 0.5rem;
    border-top: 1px solid currentColor;
    opacity: 0.3;
}

::deep .preview-font-small {
    font-size: 0.8rem;
}

::deep .preview-font-medium {
    font-size: 1rem;
}

::deep .preview-font-large {
    font-size: 1.2rem;
}

::deep .preview-compact {
    padding: 0.5rem;
    line-height: 1.2;
}

::deep .preview-compact .preview-header,
::deep .preview-compact .preview-body,
::deep .preview-compact .preview-footer {
    margin-bottom: 0.25rem;
    padding-bottom: 0.25rem;
}

